target.css:
:root {
  --card-bg: #ffffff;
  --header-bg: #0f4c81;
  --accent: #f59e0b;
  --accent-light: #fef3c7;
  --text-primary: #1e293b;
  --text-secondary: #64748b;
  --text-on-dark: #ffffff;
  --category-title-color: #0f4c81;
  --item-checked-label: #94a3b8;
  --item-unchecked-label: #1e293b;
  --check-checked-bg: #0f4c81;
  --check-unchecked-bg: #ffffff;
  --check-unchecked-border: #cbd5e1;
  --check-mark-color: #ffffff;
  --progress-track: #e2e8f0;
  --progress-fill: #f59e0b;
  --divider: #e2e8f0;
  --category-gap: #f8fafc;
}

body {
  display: flex;
  align-items: center;
  justify-content: center;
  min-height: 100vh;
  margin: 0;
  padding: 20px;
  box-sizing: border-box;
}

.checklist-card {
  background: var(--card-bg);
  border-radius: 16px;
  width: 520px;
  overflow: hidden;
  border: 1px solid var(--divider);
}

.card-header {
  background: var(--header-bg);
  padding: 16px 20px;
  display: flex;
  align-items: center;
  justify-content: space-between;
}

.header-left {
  display: flex;
  align-items: center;
  gap: 12px;
}

.card-icon {
  font-size: 28px;
  line-height: 1;
}

.card-title {
  margin: 0;
  font-size: 18px;
  font-weight: 700;
  color: var(--text-on-dark);
  line-height: 1.2;
}

.card-subtitle {
  margin: 2px 0 0;
  font-size: 12px;
  color: var(--accent);
  font-weight: 500;
  line-height: 1;
}

.progress-badge {
  display: flex;
  align-items: baseline;
  gap: 2px;
  background: rgba(255,255,255,0.15);
  border-radius: 10px;
  padding: 6px 12px;
}

.progress-num {
  font-size: 22px;
  font-weight: 800;
  color: var(--accent);
  line-height: 1;
}

.progress-label {
  font-size: 14px;
  font-weight: 500;
  color: var(--text-on-dark);
}

.progress-bar-track {
  background: var(--progress-track);
  height: 6px;
  width: 100%;
}

.progress-bar-fill {
  background: var(--progress-fill);
  height: 6px;
  width: 78.57%;
  border-radius: 0 4px 4px 0;
}

.categories {
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  gap: 0;
}

.category {
  padding: 14px 16px;
  border-right: 1px solid var(--divider);
}

.category:last-child {
  border-right: none;
}

.category-title {
  margin: 0 0 10px;
  font-size: 11px;
  font-weight: 700;
  text-transform: uppercase;
  letter-spacing: 0.08em;
  color: var(--category-title-color);
}

.item-list {
  display: flex;
  flex-direction: column;
  gap: 8px;
}

.item {
  display: flex;
  align-items: center;
  gap: 8px;
}

.check-box {
  width: 16px;
  height: 16px;
  border-radius: 4px;
  flex-shrink: 0;
  display: flex;
  align-items: center;
  justify-content: center;
}

.checked-box {
  background: var(--check-checked-bg);
  border: none;
}

.checked-box::after {
  content: '✓';
  color: var(--check-mark-color);
  font-size: 10px;
  font-weight: 700;
  line-height: 1;
}

.unchecked-box {
  background: var(--check-unchecked-bg);
  border: 2px solid var(--check-unchecked-border);
}

.item-label {
  font-size: 13px;
  line-height: 1.2;
}

.item.checked .item-label {
  color: var(--item-checked-label);
  text-decoration: line-through;
}

.item.unchecked .item-label {
  color: var(--item-unchecked-label);
  font-weight: 500;
}

